	@Test
	public void indexesEveryReachableNodeAndPreservesOriginTags() throws Exception {
		StatementPattern left = new StatementPattern(Var.of("s"), Var.of("leftP"), Var.of("leftO"));
		left.setOptimizationTag(QueryScopeSeed.originTag(7));
		StatementPattern right = new StatementPattern(Var.of("s"), Var.of("rightP"), Var.of("rightO"));
		QueryRoot root = new QueryRoot(new Join(left, right));
		List<QueryModelNode> expected = new ArrayList<>();
		root.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(QueryModelNode node) {
				expected.add(node);
				super.meetNode(node);
			}
		});

		Class<?> arenaType = Class.forName(
				"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope.NodeArena");
		Method indexTree = method(arenaType, "indexTree", QueryModelNode.class);
		Object arena = indexTree.invoke(null, root);
		Method size = method(arenaType, "size");
		Method id = method(arenaType, "id", QueryModelNode.class);
		Method node = method(arenaType, "node", int.class);
		Method parent = method(arenaType, "parent", int.class);
		Method postOrder = method(arenaType, "postOrder");

		assertThat(size.invoke(arena)).isEqualTo(expected.size());
		for (QueryModelNode expectedNode : expected) {
			int nodeId = (int) id.invoke(arena, expectedNode);
			assertThat(nodeId).isNotNegative();
			assertThat(node.invoke(arena, nodeId)).isSameAs(expectedNode);
			assertThat((int) expectedNode.getOptimizationTag() - 1).isEqualTo(nodeId);
			if (expectedNode == root) {
				assertThat(parent.invoke(arena, nodeId)).isEqualTo(-1);
			} else {
				assertThat((int) parent.invoke(arena, nodeId)).isNotNegative();
			}
		}
		assertThat(QueryScopeSeed.originId(left.getOptimizationTag())).isEqualTo(7);
		int[] order = (int[]) postOrder.invoke(arena);
		assertThat(order).hasSize(expected.size());
		assertThat(order[order.length - 1]).isEqualTo(id.invoke(arena, root));
	}

