	@Test
	public void primitiveMaskAndScalarOperationsAgreeAcrossLayouts() {
		for (int symbols : new int[] { 0, 1, 64, 65, 128, 129, 257 }) {
			FactIndex facts = FactIndex.allocate(2, symbols);
			facts.setFrame(0, 3);
			facts.setRegion(0, 4);
			facts.setEnvironment(0, 5);
			facts.setFlags(0, 6);
			facts.setResultKind(0, AbstractFactIndex.RESULT_SEQUENCE);
			facts.setFingerprint(0, 7L);
			if (symbols > 0) {
				facts.setBit(SemanticMask.MAY_BIND, 0, 0);
				facts.setBit(SemanticMask.MAY_BIND, 0, symbols - 1);
				facts.setBit(SemanticMask.MUST_BIND, 1, symbols - 1);
				facts.union(SemanticMask.SCOPE_OUT, 1, SemanticMask.MAY_BIND, 0, SemanticMask.MUST_BIND, 1);
				assertThat(facts.contains(SemanticMask.SCOPE_OUT, 1, 0)).isTrue();
				assertThat(facts.contains(SemanticMask.SCOPE_OUT, 1, symbols - 1)).isTrue();
				assertThat(facts.intersects(SemanticMask.MAY_BIND, 0, SemanticMask.MUST_BIND, 1)).isTrue();
				assertThat(facts.subsetOf(SemanticMask.MUST_BIND, 1, SemanticMask.MAY_BIND, 0)).isTrue();
			}

			facts.ensureCapacity(80);
			assertThat(facts.nodeCapacity()).isGreaterThanOrEqualTo(80);
			assertThat(facts.frame(0)).isEqualTo(3);
			assertThat(facts.region(0)).isEqualTo(4);
			assertThat(facts.environment(0)).isEqualTo(5);
			assertThat(facts.flags(0)).isEqualTo(6);
			assertThat(facts.resultKind(0)).isEqualTo(AbstractFactIndex.RESULT_SEQUENCE);
			assertThat(facts.fingerprint(0)).isEqualTo(7L);
			if (symbols > 0) {
				assertThat(facts.contains(SemanticMask.MAY_BIND, 0, symbols - 1)).isTrue();
			}

			facts.clear(2);
			assertThat(facts.frame(0)).isZero();
			assertThat(facts.resultKind(0)).isEqualTo(AbstractFactIndex.RESULT_MULTISET);
			for (int word = 0; word < facts.wordCount(); word++) {
				assertThat(facts.word(SemanticMask.MAY_BIND, 0, word)).isZero();
			}
		}
	}

