	private static StatementPattern pattern(String first, String second) {
		return new StatementPattern(Var.of(first), Var.of("_p", SimpleValueFactory.getInstance().createIRI("urn:p")),
				Var.of(second));
	}

	private static final class CustomValueConstant extends ValueConstant {

		private CustomValueConstant() {
			super(SimpleValueFactory.getInstance().createLiteral(true));
		}
	}

	@SuppressWarnings("unchecked")
	private static void assertFastSlowParity(QueryModelNode node) throws Exception {
		QueryModelNode root = node.getParentNode() instanceof QueryRoot
				? node.getParentNode()
				: new QueryRoot((TupleExpr) node);
		ScopeAnalysis fast = ScopeAnalysis.analyze(root);
		Class<?> slowType = Class.forName(
				"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope.SlowReferenceAnalyzer");
		Object slow = method(slowType, "analyze", QueryModelNode.class).invoke(null, root);
		Method names = method(slowType, "names", SemanticMask.class, QueryModelNode.class);
		for (SemanticMask mask : SemanticMask.values()) {
			assertThat((Set<String>) names.invoke(slow, mask, node))
					.as("%s on %s", mask, node.getSignature())
					.isEqualTo(fast.names(mask, node));
		}
	}

	private static void assertLayout(Object facts, String className, int words, Object mask,
			Class<? extends Enum> maskType, int firstSymbol, int secondSymbol) throws Exception {
		assertThat(facts.getClass().getSimpleName()).isEqualTo(className);
		Method wordCount = method(facts.getClass(), "wordCount");
		Method setBit = method(facts.getClass(), "setBit", maskType, int.class, int.class);
		Method contains = method(facts.getClass(), "contains", maskType, int.class, int.class);
		assertThat(wordCount.invoke(facts)).isEqualTo(words);
		setBit.invoke(facts, mask, 0, firstSymbol);
		setBit.invoke(facts, mask, 0, secondSymbol);
		assertThat(contains.invoke(facts, mask, 0, firstSymbol)).isEqualTo(true);
		assertThat(contains.invoke(facts, mask, 0, secondSymbol)).isEqualTo(true);
	}

	private static Method method(Class<?> type, String name, Class<?>... parameterTypes) throws Exception {
		Method method;
		try {
			method = type.getMethod(name, parameterTypes);
		} catch (NoSuchMethodException e) {
			method = type.getDeclaredMethod(name, parameterTypes);
		}
		method.setAccessible(true);
		return method;
	}

	private static void withFunction(Function function, Runnable action) {
		FunctionRegistry registry = FunctionRegistry.getInstance();
		Optional<Function> previous = registry.add(function);
		try {
			action.run();
		} finally {
			registry.remove(function);
			previous.ifPresent(registry::add);
		}
	}

	private static final class TestFunction implements Function {

		private final String uri;
		private final boolean differentResult;

		private TestFunction(String uri, boolean differentResult) {
			this.uri = uri;
			this.differentResult = differentResult;
		}

		@Override
		public String getURI() {
			return uri;
		}

		@Override
		@SuppressWarnings("deprecation")
		public Value evaluate(ValueFactory valueFactory, Value... args) {
			return valueFactory.createLiteral(uri);
		}

		@Override
		public boolean mustReturnDifferentResult() {
			return differentResult;
		}
	}
